// Pega os dados
const ultima_mensagem_da_fila = $input.last();
const mensagem_do_workflow = $('Info').first();

// Extrai os IDs como STRING (Nunca converta ID de API para Number)
const idFila = String(ultima_mensagem_da_fila.json.id_mensagem || '');
const idWorkflow = String(mensagem_do_workflow.json.id_mensagem || '');

// --- LOGS DE DEBUG ---
// Abra o Console do Navegador (F12) para ver isso rodando
console.log("🔍 --- DEBUG MENSAGEM ENCAVALADA ---");
console.log(`📥 ID Fila (O que acabou de chegar): "${idFila}"`);
console.log(`💾 ID Workflow (O que o fluxo está processando): "${idWorkflow}"`);

// Verifica se há IDs válidos antes de comparar
if (!idFila || !idWorkflow) {
  console.log("⚠️ ALERTA: Um dos IDs está vazio ou undefined.");
}

// Comparação Estrita de Strings
if (idFila !== idWorkflow) {
  console.log("❌ CONFLITO DETECTADO: Mensagem encavalada. Parando o fluxo.");
  console.log(`Motivo: "${idFila}" é diferente de "${idWorkflow}"`);

  // Retorna vazio para parar o fluxo
  return []; 
}

console.log("✅ SUCESSO: IDs coincidem. Fluxo continua.");

// Pass-through da fila de mensagens
return $input.all();

