(() => {
  const inicioRaw = (($fromAI('data_hora_inicio') || '') + '').trim();
  const fimRaw = (($fromAI('data_hora_fim') || '') + '').trim();

  const inicioBase = DateTime.fromISO(inicioRaw, { setZone: true });
  const fimBase = DateTime.fromISO(fimRaw, { setZone: true });

  if (!inicioBase.isValid) throw new Error('data_hora_inicio_invalida');
  if (!fimBase.isValid) throw new Error('data_hora_fim_invalida');

  const inicio = inicioBase.setZone('America/Sao_Paulo');
  const fim = fimBase.setZone('America/Sao_Paulo');
  const agora = DateTime.now().setZone('America/Sao_Paulo');

  if (fim <= inicio) throw new Error('intervalo_invalido');
  if (inicio.hasSame(agora, 'day') && inicio <= agora) {
    throw new Error('horario_passado');
  }

  const nomeBarbeiroRaw = (($fromAI('nome_barbeiro') || '') + '').trim();
  const profissional = !nomeBarbeiroRaw || /^indiferente$/i.test(nomeBarbeiroRaw)
    ? 'Indiferente'
    : nomeBarbeiroRaw;

  return JSON.stringify({
    start: {
      dateTime: inicio.toISO()
    },
    end: {
      dateTime: fim.toISO()
    },
    summary: `[${profissional}] ${(($fromAI('nome_cliente') || '') + '').trim()} - ${(($fromAI('servico') || '') + '').trim()}`,
    description: `Cliente: ${(($fromAI('nome_cliente') || '') + '').trim()}\nTelefone: ${$('Info').first().json.telefone}\nServiço: ${(($fromAI('servico') || '') + '').trim()}\nProfissional: ${profissional}\nUnidade: ${(($fromAI('unidade') || '') + '').trim()}\nStatus: aguardando_confirmacao\nOrigem: IA/WhatsApp`,
    colorId: '5'
  });
})()
}}

