let items = $input.all();
if (items.length === 0) {
  return [{ json: { lista_menu: 'Nenhuma unidade disponível no momento.', lista_prompt: '' } }];
}

let unidades = items[0].json;
if (!Array.isArray(unidades)) {
  unidades = items.map(i => i.json);
}

if (!Array.isArray(unidades) || unidades.length === 0) {
  return [{ json: { lista_menu: 'Nenhuma unidade disponível no momento.', lista_prompt: '' } }];
}

const emojis = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];

const lista_menu = unidades
  .map((u, i) => `${emojis[i] || (i+1)+'.'} ${u.nome_fantasia}`)
  .join('\n\n');

const lista_prompt = unidades
  .map((u, i) => `- ${i+1}: ${u.nome_fantasia}`)
  .join('\n');

return [{ json: { lista_menu, lista_prompt, unidades } }];
